#define REG_DISPCNT *(volatile unsigned short*)0x4000000
#define MODE3 0x0003
#define BG2_ENABLE 0x0400
#define SCREENBUFFER ((volatile unsigned short*)0x6000000)

int main() {
  REG_DISPCNT = MODE3 | BG2_ENABLE;
  for(int i=0; i<240*160; i++) SCREENBUFFER[i] = 0x1F;
  while(1);
  return 0;
}

